    let isJailbroken: Bool
    let isDebugged: Bool
    let isRunningInEmulator: Bool
    let isTampered: Bool
    let isReverseEngineered: Bool
    let hasHookingFrameworks: Bool
    let threatLevel: IntegrityThreatLevel
    let details: [String]
    
    var isCompromised: Bool {
        return threatLevel >= .medium
    }
    
    var isCriticallyCompromised: Bool {
        return threatLevel >= .high
    }
}

