// MARK: - SecureKeyStorage.swift

import Security
import CryptoKit
import LocalAuthentication

enum KeyStorageError: Error, LocalizedError {
    case keychainError(OSStatus)
    case keyNotFound
    case biometricFailed
    case dataConversionFailed
    case integrityCheckFailed(String)
    case encryptionFailed
    case decryptionFailed
    
    var errorDescription: String? {
        switch self {
        case .keychainError(let status):
            return "Keychain error: \(status)"
        case .keyNotFound:
            return "Key not found in secure storage"
        case .biometricFailed:
            return "Biometric authentication failed"
        case .dataConversionFailed:
            return "Data conversion failed"
        case .integrityCheckFailed(let reason):
            return "Integrity check failed: \(reason)"
        case .encryptionFailed:
            return "Encryption failed"
        case .decryptionFailed:
            return "Decryption failed"
        }
    }
}

class SecureKeyStorage {
    private let serviceName = "com.cryptowallet.keystore"
    private let integrityManager: DeviceIntegrityManager
    
    // Additional encryption layer key derived from device-specific data
    private var storageEncryptionKey: SymmetricKey?
    
    init(integrityManager: DeviceIntegrityManager) {
        self.integrityManager = integrityManager
        self.storageEncryptionKey = deriveStorageKey()
    }
    
    // MARK: - Storage Key Derivation
    
    private func deriveStorageKey() -> SymmetricKey? {
        // Derive an additional encryption key using device-specific info
        let bundleId = Bundle.main.bundleIdentifier ?? "com.cryptowallet"
        let deviceId = UIDevice.current.identifierForVendor?.uuidString ?? "unknown"
        let salt = "\(bundleId).\(deviceId).storage.key"
        
        guard let saltData = salt.data(using: .utf8) else { return nil }
        let keyMaterial = SHA256.hash(data: saltData)
        return SymmetricKey(data: keyMaterial)
    }
    
    // MARK: - Store Private Key
    
    func storePrivateKey(_ privateKeyData: Data, forAddress address: String) throws {
        // Integrity gate
        let integrityCheck = integrityManager.canPerformSensitiveOperation()
        guard integrityCheck.allowed else {
            throw KeyStorageError.integrityCheckFailed(integrityCheck.reason ?? "Unknown")
        }
        
        // Apply additional encryption layer
        let encryptedData = try applyAdditionalEncryption(privateKeyData)
        
        // Create access control with biometric + device passcode
        var error: Unmanaged<CFError>?
        guard let accessControl = SecAccessControlCreateWithFlags(
            kCFAllocatorDefault,
            kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            [.biometryCurrentSet, .privateKeyUsage],
            &error
        ) else {
            throw KeyStorageError.keychainError(-1)
        }
        
        // Delete existing key if present
        let deleteQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: address
        ]
        SecItemDelete(deleteQuery as CFDictionary)
        
        // Store with maximum security attributes
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: address,
            kSecValueData as String: encryptedData,
            kSecAttrAccessControl as String: accessControl,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            kSecAttrSynchronizable as String: false, // Never sync to iCloud
            kSecAttrIsInvisible as String: true
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw KeyStorageError.keychainError(status)
        }
    }
    
    // MARK: - Retrieve Private Key
    
    func retrievePrivateKey(forAddress address: String) throws -> Data {
        // Integrity gate
        let integrityCheck = integrityManager.canPerformSensitiveOperation()
        guard integrityCheck.allowed else {
            throw KeyStorageError.integrityCheckFailed(integrityCheck.reason ?? "Unknown")
        }
        
        let context = LAContext()
        context.localizedReason = "Authenticate to access your wallet key"
        context.touchIDAuthenticationAllowableReuseDuration = 0 // Always require fresh auth
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: address,
            kSecReturnData as String: true,
            kSecUseAuthenticationContext as String: context,
            kSecUseOperationPrompt as String: "Authenticate to access your private key"
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let encryptedData = result as? Data else {
            if status == errSecItemNotFound {
                throw KeyStorageError.keyNotFound
            }
            throw KeyStorageError.keychainError(status)
        }
        
        // Remove additional encryption layer
        let decryptedData = try removeAdditionalEncryption(encryptedData)
        return decryptedData
    }
    
    // MARK: - Delete Private Key
    
    func deletePrivateKey(forAddress address: String) throws {
        let integrityCheck = integrityManager.canPerformSensitiveOperation()
        guard integrityCheck.allowed else {
            throw KeyStorageError.integrityCheckFailed(integrityCheck.reason ?? "Unknown")
        }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: address
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw KeyStorageError.keychainError(status)
        }
    }
    
    // MARK: - Additional Encryption Layer
    
    private func applyAdditionalEncryption(_ data: Data) throws -> Data {
        guard let key = storageEncryptionKey else {
            throw KeyStorageError.encryptionFailed
        }
        
        let sealedBox = try AES.GCM.seal(data, using: key)
        guard let combined = sealedBox.combined else {
            throw KeyStorageError.encryptionFailed
        }
        return combined
    }
    
    private func removeAdditionalEncryption(_ data: Data) throws -> Data {
        guard let key = storageEncryptionKey else {
            throw KeyStorageError.decryptionFailed
        }
        
        let sealedBox = try AES.GCM.SealedBox(combined: data)
        let decryptedData = try AES.GCM.open(sealedBox, using: key)
        return decryptedData
    }
    
    // MARK: - List Stored Addresses
    
    func listStoredAddresses() -> [String] {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecReturnAttributes as String: true,
            kSecMatchLimit as String: kSecMatchLimitAll
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let items = result as? [[String: Any]] else {
            return []
        }
        
        return items.compactMap { $0[kSecAttrAccount as String] as? String }
    }
}

