    }()
    
    init(integrityManager: DeviceIntegrityManager) {
        self.integrityManager = integrityManager
    }
    
    // MARK: - Generate Mnemonic
    
    func generateMnemonic(wordCount: Int = 12) throws -> String {
        // Integrity gate
        let integrityCheck = integrityManager.canPerformSensitiveOperation()
        guard integrityCheck.allowed else {
            throw KeyGenerationError.integrityCheckFailed(integrityCheck.reason ?? "Unknown")
        }
        
        let entropyBits: Int
        switch wordCount {
        case 12: entropyBits = 128
        case 15: entropyBits = 160
        case 18: entropyBits = 192
        case 21: entropyBits = 224
        case 24: entropyBits = 256
        default: entropyBits = 128
        }
        
        let entropyBytes = entropyBits / 8
        var entropy = Data(count: entropyBytes)
        let result = entropy.withUnsafeMutableBytes { bufferPointer in
            SecRandomCopyBytes(kSecRandomDefault, entropyBytes, bufferPointer.baseAddress!)
        }
        
        guard result == errSecSuccess else {
            throw KeyGenerationError.randomGenerationFailed
        }
        
        // Calculate checksum
        let hash = SHA256.hash(data: entropy)
        let hashData = Data(hash)
        
        // Combine entropy + checksum bits
        var bits = ""
        for byte in entropy {
            bits += String(byte, radix: 2).leftPadded(toLength: 8, withPad: "0")
        }
        
        let checksumBits = entropyBits / 32
        let firstHashByte = hashData[0]
        let checksumString = String(firstHashByte, radix: 2).leftPadded(toLength: 8, withPad: "0")
        bits += String(checksumString.prefix(checksumBits))
        
        // Convert to word indices
        var words: [String] = []
        for i in stride(from: 0, to: bits.count, by: 11) {
            let startIndex = bits.index(bits.startIndex, offsetBy: i)
            let endIndex = bits.index(startIndex, offsetBy: min(11, bits.count - i))
            let indexBits = String(bits[startIndex..<endIndex])
            
            if let wordIndex = Int(indexBits, radix: 2), wordIndex < Self.bip39Words.count {
                words.append(Self.bip39Words[wordIndex])
            }
        }
        
        return words.joined(separator: " ")
    }
    
    // MARK: - Generate Key Pair from Mnemonic
    
    func generateKeyPair(fromMnemonic mnemonic: String, passphrase: String = "") throws -> WalletKeyPair {
        // Integrity gate
        let integrityCheck = integrityManager.canPerformSensitiveOperation()
        guard integrityCheck.allowed else {
            throw KeyGenerationError.integrityCheckFailed(integrityCheck.reason ?? "Unknown")
        }
        
        // Derive seed from mnemonic using PBKDF2
        let mnemonicData = mnemonic.decomposedStringWithCompatibilityMapping.data(using: .utf8)!
        let salt = ("mnemonic" + passphrase).decomposedStringWithCompatibilityMapping.data(using: .utf8)!
        
        let seed = try pbkdf2(password: mnemonicData, salt: salt, iterations: 2048, keyLength: 64)
        
        // Use first 32 bytes as private key (simplified - production should use BIP32/44 derivation)
        let privateKeyData = seed.prefix(32)
        
        // Generate public key using Curve25519 (for demonstration)
        // In production Ethereum wallet, use secp256k1
        let privateKey = Curve25519.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let publicKey = privateKey.publicKey
        
        // Generate address (simplified - hash of public key)
        let publicKeyHash = SHA256.hash(data: publicKey.rawRepresentation)
        let addressData = Data(publicKeyHash).suffix(20)
        let address = "0x" + addressData.map { String(format: "%02x", $0) }.joined()
        
        return WalletKeyPair(
            privateKey: Data(privateKeyData),
            publicKey: publicKey.rawRepresentation,
            address: address
        )
    }
    
    // MARK: - Generate Key Pair (Random)
    
    func generateRandomKeyPair() throws -> WalletKeyPair {
        let integrityCheck = integrityManager.canPerformSensitiveOperation()
        guard integrityCheck.allowed else {
            throw KeyGenerationError.integrityCheckFailed(integrityCheck.reason ?? "Unknown")
        }
        
        var privateKeyBytes = Data(count: 32)
        let result = privateKeyBytes.withUnsafeMutableBytes { bufferPointer in
            SecRandomCopyBytes(kSecRandomDefault, 32, bufferPointer.baseAddress!)
        }
        
        guard result == errSecSuccess else {
            throw KeyGenerationError.randomGenerationFailed
        }
        
        let privateKey = Curve25519.Signing.PrivateKey(rawRepresentation: privateKeyBytes)
        let publicKey = privateKey.publicKey
        
        let publicKeyHash = SHA256.hash(data: publicKey.rawRepresentation)
        let addressData = Data(publicKeyHash).suffix(20)
        let address = "0x" + addressData.map { String(format: "%02x", $0) }.joined()
        
        return WalletKeyPair(
            privateKey: privateKeyBytes,
            publicKey: publicKey.rawRepresentation,
            address: address
        )
    }
    
    // MARK: - PBKDF2
    
    private func pbkdf2(password: Data, salt: Data, iterations: Int, keyLength: Int) throws -> Data {
        var derivedKey = Data(count: keyLength)
        
        let result = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            password.withUnsafeBytes { passwordBytes in
                salt.withUnsafeBytes { saltBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                        password.count,
                        saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        salt.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA512),
                        UInt32(iterations),
                        derivedKeyBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        keyLength
                    )
                }
            }
        }
        
        guard result == kCCSuccess else {
            throw KeyGenerationError.keyDerivationFailed
        }
        
        return derivedKey
    }
}

// MARK: - String Extension

extension String {
    func leftPadded(toLength length: Int, withPad pad: String) -> String {
        let deficit = length - self.count
        if deficit <= 0 { return self }
        return String(repeating: pad, count: deficit) + self
    }
}

// MARK: - TransactionSigner.swift

import CryptoKit

struct Transaction {
    let from: String
    let to: String
    let value: String // In wei
    let nonce: UInt64
    let gasPrice: String
    let gasLimit: UInt64
    let data: Data?
    let chainId: UInt64
    
    var serialized: Data {
        // Simplified RLP-like serialization
        var payload = Data()
        payload.append(contentsOf: withUnsafeBytes(of: nonce.bigEndian) { Data($0) })
        payload.append(gasPrice.data(using: .utf8) ?? Data())
        payload.append(contentsOf: withUnsafeBytes(of: gasLimit.bigEndian) { Data($0) })
        payload.append(to.data(using: .utf8) ?? Data())
        payload.append(value.data(using: .utf8) ?? Data())
        if let txData = data {
            payload.append(txData)
        }
        payload.append(contentsOf: withUnsafeBytes(of: chainId.bigEndian) { Data($0) })
        return payload
    }
}

struct SignedTransaction {
    let transaction: Transaction
    let signature: Data
    let transactionHash: String
    let rawTransaction: String
}

enum TransactionSigningError: Error, LocalizedError {
    case invalidPrivateKey
    case signingFailed
    case integrityCheckFailed(String)
    case invalidTransaction(String)
    
    var errorDescription: String? {
        switch self {
        case .invalidPrivateKey: return "Invalid private key"
        case .signingFailed: return "Transaction signing failed"
        case .integrityCheckFailed(let reason): return "Integrity check failed: \(reason)"
        case .invalidTransaction(let reason): return "Invalid transaction: \(reason)"
        }
    }
}

class TransactionSigner {
    private let integrityManager: DeviceIntegrityManager
    private let keyStorage: SecureKeyStorage
    
    init(integrityManager: DeviceIntegrityManager, keyStorage: SecureKeyStorage) {
        self.integrityManager = integrityManager
        self.keyStorage = keyStorage
    }
    
    // MARK: - Sign Transaction
    
    func signTransaction(_ transaction: Transaction) throws -> SignedTransaction {
        // Critical integrity gate - signing is the highest risk operation
        let integrityCheck = integrityManager.canPerformSensitiveOperation()
        guard integrityCheck.allowed else {
            throw TransactionSigningError.integrityCheckFailed(integrityCheck.reason ?? "Unknown")
        }
        
        // Validate transaction
        try validateTransaction(transaction)
        
        // Retrieve private key (requires biometric auth via SecureKeyStorage)
        let privateKeyData = try keyStorage.retrievePrivateKey(forAddress: transaction.from)
        
        // Create signing key
        let privateKey = try Curve25519.Signing.PrivateKey(rawRepresentation: privateKeyData)
        
        // Hash the transaction
        let txData = transaction.serialized
        let txHash = SHA256.hash(data: txData)
        let txHashData = Data(txHash)
        
        // Sign the hash
        let signature = try privateKey.signature(for: txHashData)
        
        // Create transaction hash
        let signedTxHash = SHA256.hash(data: signature + txData)
        let hashString = "0x" + Data(signedTxHash).map { String(format: "%02x", $0) }.joined()
        
        // Create raw transaction hex
        let rawTx = "0x" + (signature + txData).map { String(format: "%02x", $0) }.joined()
        
        // Zero out private key data from memory
        // Note: In Swift, we can't guarantee memory zeroing, but we minimize exposure
        
        return SignedTransaction(
            transaction: transaction,
            signature: signature,
            transactionHash: hashString,
            rawTransaction: rawTx
        )
    }
    
    // MARK: - Sign Message
    
    func signMessage(_ message: String, fromAddress address: String) throws -> Data {
        let integrityCheck = integrityManager.canPerformSensitiveOperation()
        guard integrityCheck.allowed else {
            throw TransactionSigningError.integrityCheckFailed(integrityCheck.reason ?? "Unknown")
        }
        
        let privateKeyData = try keyStorage.retrievePrivateKey(forAddress: address)
        let privateKey = try Curve25519.Signing.PrivateKey(rawRepresentation: privateKeyData)
        
        // Ethereum-style message prefix
        let prefix = "\u{19}Ethereum Signed Message:\n\(message.count)"
        let prefixedMessage = prefix + message
        
        guard let messageData = prefixedMessage.data(using: .utf8) else {
            throw TransactionSigningError.signingFailed
        }
        
        let messageHash = SHA256.hash(data: messageData)
        let signature = try privateKey.signature(for: Data(messageHash))
        
        return signature
    }
    
    // MARK: - Transaction Validation
    
    private func validateTransaction(_ transaction: Transaction) throws {
        // Validate addresses
        guard transaction.from.hasPrefix("0x"), transaction.from.count == 42 else {
            throw TransactionSigningError.invalidTransaction("Invalid from address")
        }
        
        guard transaction.to.hasPrefix("0x"), transaction.to.count == 42 else {
            throw TransactionSigningError.invalidTransaction("Invalid to address")
        }
        
        // Validate value
        guard let _ = UInt64(transaction.value) else {
            throw TransactionSigningError.invalidTransaction("Invalid value")
        }
        
        // Validate gas
        guard transaction.gasLimit > 0 else {
            throw TransactionSigningError.invalidTransaction("Gas limit must be positive")
        }
        
        // Validate chain ID
        guard transaction.chainId > 0 else {
            throw TransactionSigningError.invalidTransaction("Invalid chain ID")
        }
    }
}

// MARK: - BlockchainService.swift

import Foundation

struct BlockchainBalance {
    let address: String
    let balance: String
    let balanceInEth: Double
}

struct TransactionReceipt {
    let transactionHash: String
    let blockNumber: UInt64
    let status: Bool
    let gasUsed: UInt64
}

enum BlockchainError: Error, LocalizedError {
    case networkError(String)
    case rpcError(String)
    case invalidResponse
    case integrityCheckFailed(String)
    
    var errorDescription: String? {
        switch self {
        case .networkError(let msg): return "Network error: \(msg)"
        case .rpcError(let msg): return "RPC error: \(msg)"
        case .invalidResponse: return "Invalid response from blockchain"
        case .integrityCheckFailed(let reason): return "Integrity check failed: \(reason)"
        }
    }
}

class BlockchainService {
    private let rpcURL: URL
    private let session: URLSession
    private let integrityManager: DeviceIntegrityManager
    
    init(rpcURL: URL, integrityManager: DeviceIntegrityManager) {
        self.rpcURL = rpcURL
        self.integrityManager = integrityManager
        
        // Configure URLSession with certificate pinning
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.urlCache = nil
        config.requestCachePolicy = .reloadIgnoringLocalCacheData
        
        self.session = URLSession(configuration: config, delegate: CertificatePinningDelegate(), delegateQueue: nil)
    }
    
    // MARK: - Get Balance
    
    func getBalance(address: String) async throws -> BlockchainBalance {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getBalance",
            "params": [address, "latest"],
            "id": 1
        ]
        
        let response = try await makeRPCCall(params: params)
        
        guard let result = response["result"] as? String else {
            throw BlockchainError.invalidResponse
        }
        
        // Convert hex to decimal
        let hexString = result.hasPrefix("0x") ? String(result.dropFirst(2)) : result
        let balanceWei = UInt64(hexString, radix: 16) ?? 0
        let balanceEth = Double(balanceWei) / 1e18
        
        return BlockchainBalance(
            address: address,
            balance: String(balanceWei),
            balanceInEth: balanceEth
        )
    }
    
    // MARK: - Get Transaction Count (Nonce)
    
    func getTransactionCount(address: String) async throws -> UInt64 {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getTransactionCount",
            "params": [address, "latest"],
            "id": 1
        ]
        
        let response = try await makeRPCCall(params: params)
        
        guard let result = response["result"] as? String else {
            throw BlockchainError.invalidResponse
        }
        
        let hexString = result.hasPrefix("0x") ? String(result.dropFirst(2)) : result
        return UInt64(hexString, radix: 16) ?? 0
    }
    
    // MARK: - Send Raw Transaction
    
    func sendRawTransaction(_ signedTransaction: SignedTransaction) async throws -> String {
        // Integrity gate for broadcasting
        let integrityCheck = integrityManager.canPerformSensitiveOperation()
        guard integrityCheck.allowed else {
            throw BlockchainError.integrityCheckFailed(integrityCheck.reason ?? "Unknown")
        }
        
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_sendRawTransaction",
            "params": [signedTransaction.rawTransaction],
            "id": 1
        ]
        
        let response = try await makeRPCCall(params: params)
        
        if let error = response["error"] as? [String: Any],
           let message = error["message"] as? String {
            throw BlockchainError.rpcError(message)
        }
        
        guard let txHash = response["result"] as? String else {
            throw BlockchainError.invalidResponse
        }
        
        return txHash
    }
    
    // MARK: - Get Transaction Receipt
    
    func getTransactionReceipt(txHash: String) async throws -> TransactionReceipt? {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getTransactionReceipt",
            "params": [txHash],
            "id": 1
        ]
        
        let response = try await makeRPCCall(params: params)
        
        guard let result = response["result"] as? [String: Any] else {
            return nil // Transaction not yet mined
        }
        
        let blockNumberHex = (result["blockNumber"] as? String ?? "0x0").dropFirst(2)
        let statusHex = (result["status"] as? String ?? "0x0").dropFirst(2)
        let gasUsedHex = (result["gasUsed"] as? String ?? "0x0").dropFirst(2)
        
        return TransactionReceipt(
            transactionHash: txHash,
            blockNumber: UInt64(blockNumberHex, radix: 16) ?? 0,
            status: statusHex == "1",
            gasUsed: UInt64(gasUsedHex, radix: 16) ?? 0
        )
    }
    
    // MARK: - Get Gas Price
    
    func getGasPrice() async throws -> String {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_gasPrice",
            "params": [],
            "id": 1
        ]
        
        let response = try await makeRPCCall(params: params)
        
        guard let result = response["result"] as? String else {
            throw BlockchainError.invalidResponse
        }
        
        return result
    }
    
    // MARK: - RPC Call
    
    private func makeRPCCall(params: [String: Any]) async throws -> [String: Any] {
        var request = URLRequest(url: rpcURL)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.timeoutInterval = 30
        
        let jsonData = try JSONSerialization.data(withJSONObject: params)
        request.httpBody = jsonData
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw BlockchainError.networkError("HTTP error")
        }
        
        guard let json = try JSONSerialization.jsonObject(with: data) as? [String: Any] else {
            throw BlockchainError.invalidResponse
        }
        
        return json
    }
}

// MARK: - Certificate Pinning Delegate

class CertificatePinningDelegate: NSObject, URLSessionDelegate {
    // In production, embed the actual certificate hashes for your RPC provider
    private let pinnedCertificateHashes: Set<String> = [
        // SHA256 hash of the expected certificate's public key
        // Example: "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA="
    ]
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // If no pins configured, use default validation (for development)
        if pinnedCertificateHashes.isEmpty {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        // Evaluate server trust
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Check certificate pinning
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        var isPinned = false
        
        for i in 0..<certificateCount {
            if let certificate = SecTrustGetCertificateAtIndex(serverTrust, i) {
                let certData = SecCertificateCopyData(certificate) as Data
                let hash = SHA256.hash(data: certData)
                let hashString = "sha256/" + Data(hash).base64EncodedString()
                
                if pinnedCertificateHashes.contains(hashString) {
                    isPinned = true
                    break
                }
            }
        }
        
        if isPinned {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// MARK: - WalletManager.swift

import SwiftUI
import Combine

struct WalletAccount: Identifiable, Codable {
    let id: UUID
    let address: String
    let name: String
    let createdAt: Date
    var balance: Double?
}

class WalletManager: ObservableObject {
    @Published var accounts: [WalletAccount] = []
    @Published var selectedAccount: WalletAccount?
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?
    @Published var successMessage: String?
    
    private var keyGenerator: KeyGenerator!
    private var keyStorage: SecureKeyStorage!
    private var transactionSigner: TransactionSigner!
    private var blockchainService: BlockchainService!
    private let integrityManager: DeviceIntegrityManager
    
    init() {
        self.integrityManager = DeviceIntegrityManager()
        setupServices()
        loadAccounts()
    }
    
    private func setupServices() {
        keyStorage = SecureKeyStorage(integrityManager: integrityManager)
        keyGenerator = KeyGenerator(integrityManager: integrityManager)
        transactionSigner = TransactionSigner(integrityManager: integrityManager, keyStorage: keyStorage)
        
        // Default to Ethereum mainnet - in production, make this configurable
        let rpcURL = URL(string: "https://mainnet.infura.io/v3/YOUR_PROJECT_ID")!
        blockchainService = BlockchainService(rpcURL: rpcURL, integrityManager: integrityManager)
    }
    
    // MARK: - Create Wallet
    
    func createWallet(name: String) async {
        await MainActor.run { isLoading = true; errorMessage = nil }
        
        do {
            // Generate mnemonic
            let mnemonic = try keyGenerator.generateMnemonic()
            
            // Generate key pair
            let keyPair = try keyGenerator.generateKeyPair(fromMnemonic: mnemonic)
            
            // Store private key securely
            try keyStorage.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
            
            let account = WalletAccount(
                id: UUID(),
                address: keyPair.address,
                name: name,
                createdAt: Date(),
                balance: 0.0
            )
            
            await MainActor.run {
                accounts.append(account)
                selectedAccount = account
                isLoading = false
                successMessage = "Wallet created! Save your recovery phrase:\n\(mnemonic)"
            }
            
            saveAccounts()
            
        } catch {
            await MainActor.run {
                isLoading = false
                errorMessage = error.localizedDescription
            }
        }
    }
    
